<template>
	<view class="community-page">
		<!-- 头部 -->
		<view class="header">
			<text class="title">社区广场</text>
			<text class="subtitle">发现邻里间的美好</text>
		</view>

		<!-- 社区统计 -->
		<view class="stats">
			<text class="stat-number">345</text>
			<text class="stat-label">邻里动态</text>
		</view>

		<!-- 分类标签（横向滚动） -->
		<scroll-view scroll-x class="tabs">
			<view
				v-for="(tab, index) in tabs"
				:key="index"
				class="tab-item"
				:class="{ active: currentTab === index }"
				@click="switchTab(index)"
			>
				{{ tab.name }}
			</view>
		</scroll-view>

		<!-- 热门话题 -->
		<view class="hot-topics">
			<view class="topic-card" @click="goTopic('volunteer')">
				<text class="topic-tag">VOLUNTEER</text>
				<text class="topic-title">周末社区环保义演招募</text>
			</view>
			<view class="topic-card" @click="goTopic('rescue')">
				<text class="topic-tag">“救助”</text>
				<text class="topic-title">流浪猫绝育计划急需志愿者</text>
			</view>
		</view>

		<!-- 动态列表 -->
		<view class="post-list">
			<view class="post-item" v-for="(post, idx) in posts" :key="idx">
				<view class="post-header">
					<!-- 移除图片，改用纯色圆形 + 首字母 -->
					<view class="avatar" :style="{ backgroundColor: post.avatarColor }">
						<text class="avatar-text">{{ post.nickname.charAt(0) }}</text>
					</view>
					<view class="user-info">
						<text class="nickname">{{ post.nickname }}</text>
						<text class="time">{{ post.time }}</text>
					</view>
					<text class="tag" :class="post.tagClass">{{ post.tag }}</text>
				</view>
				<text class="content">{{ post.content }}</text>
				<view class="actions">
					<text @click="likePost(idx)" :class="{ active: post.liked }">👍 {{ post.likes }}</text>
					<text @click="dislikePost(idx)" :class="{ active: post.disliked }">👎 {{ post.dislikes }}</text>
					<text @click="commentPost(idx)">💬 {{ post.comments }}</text>
					<text class="points">+{{ post.points }}积分</text>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
export default {
	data() {
		return {
			currentTab: 0,
			tabs: [
				{ name: '志愿者', type: 'volunteer' },
				{ name: '好人好事', type: 'good' },
				{ name: '爱心捐款', type: 'donate' },
				{ name: '日常分享', type: 'share' },
				{ name: '积分商城', type: 'points' }
			],
			posts: [
				{
					nickname: '王大爷',
					time: '1小时前',
					tag: '#好人好事',
					tagClass: 'good',
					content: '今天在小区车库出口捡到了一个钱包，已经交给保安亭并物归原主啦。大家出行要注意安全，看管好随身物品。',
					likes: 12,
					dislikes: 4,
					comments: 0,
					points: 5,
					liked: false,
					disliked: false,
					avatarColor: '#6b8c42' // 可自定义不同颜色
				},
				{
					nickname: '李小美',
					time: '3小时前',
					tag: '#日常分享',
					tagClass: 'share',
					content: '楼下的樱花开得正好，下午阳光洒进来的时候真的好美！推荐大家去南门附近打卡。',
					likes: 12,
					dislikes: 4,
					comments: 0,
					points: 2,
					liked: false,
					disliked: false,
					avatarColor: '#2d8cf0'
				},
				{
					nickname: '张先生',
					time: '8小时前',
					tag: '#爱心捐款',
					tagClass: 'donate',
					content: '刚刚为社区微型图书馆捐赠了20本精装童话书，希望给孩子们带去不一样的童年。',
					likes: 12,
					dislikes: 4,
					comments: 0,
					points: 10,
					liked: false,
					disliked: false,
					avatarColor: '#e67e22'
				}
			]
		};
	},
	methods: {
		switchTab(index) {
			this.currentTab = index;
			uni.showToast({
				title: `${this.tabs[index].name}分类开发中`,
				icon: 'none'
			});
		},
		likePost(idx) {
			const post = this.posts[idx];
			if (!post.liked) {
				post.likes++;
				post.liked = true;
				if (post.disliked) {
					post.dislikes--;
					post.disliked = false;
				}
				uni.showToast({
					title: `+${post.points}积分`,
					icon: 'none'
				});
			} else {
				post.likes--;
				post.liked = false;
			}
		},
		dislikePost(idx) {
			const post = this.posts[idx];
			if (!post.disliked) {
				post.dislikes++;
				post.disliked = true;
				if (post.liked) {
					post.likes--;
					post.liked = false;
				}
			} else {
				post.dislikes--;
				post.disliked = false;
			}
		},
		commentPost(idx) {
			uni.showToast({
				title: '评论功能开发中',
				icon: 'none'
			});
		},
		goTopic(type) {
			uni.showToast({
				title: `话题“${type === 'volunteer' ? '周末社区环保义演招募' : '流浪猫绝育计划'}”开发中`,
				icon: 'none'
			});
		}
	}
};
</script>

